lines = []
# ReportTab
lines.append('')
lines.append('// ─── REPORT TAB ───────────────────────────────────────────────────────────────')
lines.append('function ReportTab({ instruments, documents, training, equipment, suppliers, ncs, auditPlans, envRecords }) {')
lines.append('  const [generated, setGenerated] = useState(false);')
lines.append('  const calibEnriched = instruments.filter(i=>i.status!=="\u514d\u6821\u6b63").map(i => ({ ...i, nextDate:addDays(i.calibratedDate,i.intervalDays), days:daysUntil(addDays(i.calibratedDate,i.intervalDays)) }));')
lines.append('  const eqEnriched = equipment.map(eq => ({ ...eq, nextDate:addDays(eq.lastMaintenance,eq.intervalDays), days:daysUntil(addDays(eq.lastMaintenance,eq.intervalDays)) }));')
lines.append('  const supEnriched = suppliers.map(s => ({ ...s, nextEvalDate:addDays(s.lastEvalDate,s.evalIntervalDays), days:daysUntil(addDays(s.lastEvalDate,s.evalIntervalDays)) }));')
lines.append('  const overdue = calibEnriched.filter(i=>i.days<0).length;')
lines.append('  const soonCalib = calibEnriched.filter(i=>i.days>=0&&i.days<=14).length;')
lines.append('  const overdueEq = eqEnriched.filter(e=>e.days<0).length;')
lines.append('  const openNcs = ncs.filter(n=>n.status!=="\u5df2\u95dc\u9589").length;')
lines.append('  const totalTraining = training.reduce((s,e)=>s+e.trainings.length,0);')
lines.append('  const auditCompleted = auditPlans.filter(a=>a.status==="\u5df2\u5b8c\u6210").length;')
lines.append('  const auditTotal = auditPlans.length;')
lines.append('  const envPassRate = envRecords.length>0?Math.round(envRecords.filter(r=>r.result==="\u5408\u683c").length/envRecords.length*100):0;')
lines.append('  const tdStyle = { padding:"7px 12px", border:"1px solid #e2e8f0" };')
lines.append('  const thStyle = { padding:"8px 12px", textAlign:"left", border:"1px solid #e2e8f0", background:"#f1f5f9" };')
lines.append('  const secStyle = { fontSize:15, fontWeight:800, color:"#0f172a", paddingLeft:12, marginBottom:14 };')
lines.append('  const conStyle = { marginTop:10, padding:12, background:"#f8fafc", borderRadius:8, fontSize:13, color:"#374151" };')
lines.append('  return (')
lines.append('    <div>')
lines.append('      <SectionHeader title="\u7a3d\u6838\u5831\u544a\u7522\u751f\u5668" color="#f472b6" />')
lines.append('      <div style={{ background:"rgba(244,114,182,0.06)", border:"1px solid rgba(244,114,182,0.2)", borderRadius:14, padding:24, marginBottom:20 }}>')
lines.append('        <div style={{ fontSize:15, color:"#f9a8d4", fontWeight:600, marginBottom:8 }}>[ISO 9001] \u81ea\u52d5\u7522\u751f ISO 9001:2015 \u7a3d\u6838\u6458\u8981\u5831\u544a</div>')
lines.append('        <div style={{ fontSize:13, color:"#64748b", lineHeight:1.7 }}>\u7cfb\u7d71\u5c07\u6839\u64da\u76ee\u524d\u8cc7\u6599\u5eab\u4e2d\u7684\u8a18\u9304\uff0c\u81ea\u52d5\u5f59\u6574\u6821\u6b63\u72c0\u614b\u3001\u8a2d\u5099\u4fdd\u990a\u3001\u8a13\u7df4\u8a18\u9304\u3001\u6587\u4ef6\u7248\u672c\u3001\u4f9b\u61c9\u5546\u8a55\u9451\u3001\u4e0d\u7b26\u5408\u8a18\u9304\u3001\u5167\u90e8\u7a3d\u6838\u5b8c\u6210\u72c0\u614b\u53ca\u5de5\u4f5c\u74b0\u5883\u76e3\u6e2c\u3002</div>')
lines.append('        <div style={{ display:"flex", gap:12, marginTop:16 }}>')
lines.append('          <button onClick={() => setGenerated(true)} style={{ background:"linear-gradient(135deg, #be185d, #ec4899)", border:"none", borderRadius:10, color:"#fff", cursor:"pointer", padding:"12px 24px", fontSize:14, fontWeight:700 }}>[+] \u7522\u751f\u7a3d\u6838\u5831\u544a</button>')
lines.append('          {generated && (<button onClick={() => window.print()} style={{ background:"rgba(244,114,182,0.15)", border:"1px solid rgba(244,114,182,0.3)", borderRadius:10, color:"#f9a8d4", cursor:"pointer", padding:"12px 24px", fontSize:14, fontWeight:700 }}>[P] \u5217\u5370 / \u5b58\u70ba PDF</button>)}')
lines.append('        </div>')
lines.append('      </div>')
lines.append('      {generated && (')
lines.append('        <div id="report-content" style={{ background:"#fff", color:"#1e293b", borderRadius:14, padding:32, fontFamily:"serif" }}>')
lines.append('          <div style={{ textAlign:"center", borderBottom:"2px solid #e2e8f0", paddingBottom:20, marginBottom:24 }}>')
lines.append('            <div style={{ fontSize:22, fontWeight:800, color:"#0f172a" }}>\u6f54\u6f94\u4f01\u696d\u6709\u9650\u516c\u53f8</div>')
lines.append('            <div style={{ fontSize:16, fontWeight:600, color:"#374151", marginTop:4 }}>ISO 9001:2015 \u54c1\u8cea\u7cfb\u7d71\u7a3d\u6838\u6458\u8981\u5831\u544a</div>')
lines.append('            <div style={{ fontSize:13, color:"#6b7280", marginTop:8 }}>\u5831\u544a\u7522\u751f\u65e5\u671f\uff1a{formatDate(new Date().toISOString().split("T")[0])} / \u5831\u544a\u7248\u672c\uff1a\u81ea\u52d5\u7522\u751f</div>')
lines.append('          </div>')
lines.append('          {/* \u4e00\u3001\u91cf\u6e2c\u8cc7\u6e90 MP-05 */}')
lines.append('          <div style={{ marginBottom:24 }}>')
lines.append('            <div style={{ ...secStyle, borderLeft:"4px solid #3b82f6" }}>\u4e00\u3001\u91cf\u6e2c\u8cc7\u6e90\u7ba1\u7406\uff08MP-05\uff09\u7a3d\u6838\u6458\u8981</div>')
lines.append('            <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}><thead><tr style={{ background:"#f1f5f9" }}>{["\u5100\u5668\u7de8\u865f","\u540d\u7a31","\u985e\u578b","\u6700\u5f8c\u6821\u6b63","\u4e0b\u6b21\u6821\u6b63","\u72c0\u614b"].map(h=>(<th key={h} style={thStyle}>{h}</th>))}</tr></thead><tbody>{calibEnriched.map(i=>(<tr key={i.id}><td style={tdStyle}>{i.id}</td><td style={tdStyle}>{i.name}</td><td style={tdStyle}>{i.type}</td><td style={tdStyle}>{formatDate(i.calibratedDate)}</td><td style={tdStyle}>{formatDate(i.nextDate)}</td><td style={{...tdStyle,color:i.days<0?"#ef4444":i.days<=14?"#f97316":"#16a34a",fontWeight:700}}>{urgencyLabel(i.days)}</td></tr>))}</tbody></table>')
lines.append('            <div style={conStyle}>\u7a3d\u6838\u7d50\u8ad6\uff1a\u5171 {instruments.length} \u53f0\u91cf\u898f\u5100\u5668\uff0c\u903e\u671f <b style={{color:"#ef4444"}}>{overdue}</b> \u53f0\uff0c14\u5929\u5167\u5230\u671f <b style={{color:"#f97316"}}>{soonCalib}</b> \u53f0\u3002{overdue>0&&" [\u8b66\u544a] \u8acb\u7acb\u5373\u5b89\u6392\u903e\u671f\u5100\u5668\u6821\u6b63\u3002"}</div>')
lines.append('          </div>')
lines.append('          {/* \u4e8c\u3001\u8a2d\u65bd\u8a2d\u5099 MP-04 */}')
lines.append('          <div style={{ marginBottom:24 }}>')
lines.append('            <div style={{ ...secStyle, borderLeft:"4px solid #f97316" }}>\u4e8c\u3001\u8a2d\u65bd\u8a2d\u5099\u7ba1\u7406\uff08MP-04\uff09\u7a3d\u6838\u6458\u8981</div>')
lines.append('            <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}><thead><tr style={{ background:"#f1f5f9" }}>{["\u8a2d\u5099\u7de8\u865f","\u540d\u7a31","\u4f4d\u7f6e","\u6700\u5f8c\u4fdd\u990a","\u4e0b\u6b21\u4fdd\u990a","\u72c0\u614b"].map(h=>(<th key={h} style={thStyle}>{h}</th>))}</tr></thead><tbody>{eqEnriched.map(eq=>(<tr key={eq.id}><td style={tdStyle}>{eq.id}</td><td style={tdStyle}>{eq.name}</td><td style={tdStyle}>{eq.location}</td><td style={tdStyle}>{formatDate(eq.lastMaintenance)}</td><td style={tdStyle}>{formatDate(eq.nextDate)}</td><td style={{...tdStyle,color:eq.days<0?"#ef4444":eq.days<=30?"#f97316":"#16a34a",fontWeight:700}}>{urgencyLabel(eq.days)}</td></tr>))}</tbody></table>')
lines.append('            <div style={conStyle}>\u7a3d\u6838\u7d50\u8ad6\uff1a\u5171 {equipment.length} \u53f0\u8a2d\u5099\uff0c\u903e\u671f\u4fdd\u990a <b style={{color:"#ef4444"}}>{overdueEq}</b> \u53f0\u3002</div>')
lines.append('          </div>')
lines.append('          {/* \u4e09\u3001\u4eba\u529b\u8cc7\u6e90 MP-03 */}')
lines.append('          <div style={{ marginBottom:24 }}>')
lines.append('            <div style={{ ...secStyle, borderLeft:"4px solid #8b5cf6" }}>\u4e09\u3001\u4eba\u529b\u8cc7\u6e90\u53ca\u8a13\u7df4\uff08MP-03\uff09\u7a3d\u6838\u6458\u8981</div>')
lines.append('            <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}><thead><tr style={{ background:"#f1f5f9" }}>{["\u54e1\u5de5\u7de8\u865f","\u59d3\u540d","\u90e8\u9580","\u8077\u7a31","\u5230\u8077\u65e5","\u8a13\u7df4\u7b46\u6578","\u5916\u8a13\u7b46\u6578","\u6709\u8b49\u66f8"].map(h=>(<th key={h} style={thStyle}>{h}</th>))}</tr></thead><tbody>{training.map(emp=>(<tr key={emp.id}><td style={tdStyle}>{emp.id}</td><td style={{...tdStyle,fontWeight:600}}>{emp.name}</td><td style={tdStyle}>{emp.dept}</td><td style={tdStyle}>{emp.role}</td><td style={tdStyle}>{formatDate(emp.hireDate)}</td><td style={{...tdStyle,fontWeight:700}}>{emp.trainings.length}</td><td style={tdStyle}>{emp.trainings.filter(t=>t.type==="\u5916\u8a13").length}</td><td style={tdStyle}>{emp.trainings.filter(t=>t.cert==="\u6709").length}</td></tr>))}</tbody></table>')
lines.append('            <div style={conStyle}>\u7a3d\u6838\u7d50\u8ad6\uff1a\u5171 {training.length} \u540d\u54e1\u5de5\uff0c\u8a13\u7df4\u8a18\u9304\u5408\u8a08 <b>{totalTraining}</b> \u7b46\u3002</div>')
lines.append('          </div>')
lines.append('          {/* \u56db\u3001\u4f9b\u61c9\u5546 MP-10 */}')
lines.append('          <div style={{ marginBottom:24 }}>')
lines.append('            <div style={{ ...secStyle, borderLeft:"4px solid #06b6d4" }}>\u56db\u3001\u63a1\u8cfc\u53ca\u4f9b\u61c9\u5546\u7ba1\u7406\uff08MP-10\uff09\u7a3d\u6838\u6458\u8981</div>')
lines.append('            <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}><thead><tr style={{ background:"#f1f5f9" }}>{["\u4f9b\u61c9\u5546\u7de8\u865f","\u540d\u7a31","\u985e\u5225","\u8a55\u9451\u5206\u6578","\u8a55\u5b9a\u7d50\u679c","\u6700\u5f8c\u8a55\u9451","\u4e0b\u6b21\u8a55\u9451"].map(h=>(<th key={h} style={thStyle}>{h}</th>))}</tr></thead><tbody>{supEnriched.map(s=>(<tr key={s.id}><td style={tdStyle}>{s.id}</td><td style={{...tdStyle,fontWeight:600}}>{s.name}</td><td style={tdStyle}>{s.category}</td><td style={{...tdStyle,fontWeight:700,color:s.evalScore>=90?"#16a34a":s.evalScore>=70?"#d97706":"#ef4444"}}>{s.evalScore}</td><td style={tdStyle}>{s.evalResult}</td><td style={tdStyle}>{formatDate(s.lastEvalDate)}</td><td style={{...tdStyle,color:s.days<0?"#ef4444":"#374151"}}>{formatDate(s.nextEvalDate)}</td></tr>))}</tbody></table>')
lines.append('            <div style={conStyle}>\u7a3d\u6838\u7d50\u8ad6\uff1a\u5171 {suppliers.length} \u5bb6\u4f9b\u61c9\u5546\uff0c\u8a55\u9451\u903e\u671f <b style={{color:"#ef4444"}}>{supEnriched.filter(s=>s.days<0).length}</b> \u5bb6\uff0c\u689d\u4ef6\u5408\u683c <b style={{color:"#eab308"}}>{suppliers.filter(s=>s.evalResult==="\u689d\u4ef6\u5408\u683c").length}</b> \u5bb6\u3002</div>')
lines.append('          </div>')
lines.append('          {/* \u4e94\u3001\u4e0d\u7b26\u5408 MP-15 */}')
lines.append('          <div style={{ marginBottom:24 }}>')
lines.append('            <div style={{ ...secStyle, borderLeft:"4px solid #ef4444" }}>\u4e94\u3001\u4e0d\u7b26\u5408\u53ca\u77ef\u6b63\u63aa\u65bd\uff08MP-15\uff09\u7a3d\u6838\u6458\u8981</div>')
lines.append('            <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}><thead><tr style={{ background:"#f1f5f9" }}>{["\u7de8\u865f","\u65e5\u671f","\u90e8\u9580","\u985e\u578b","\u56b4\u91cd\u5ea6","\u7c21\u8ff0","\u8cc7\u4efb\u4eba","\u5230\u671f\u65e5","\u72c0\u614b"].map(h=>(<th key={h} style={thStyle}>{h}</th>))}</tr></thead><tbody>{ncs.map(nc=>(<tr key={nc.id}><td style={{...tdStyle,fontFamily:"monospace",fontSize:11}}>{nc.id}</td><td style={tdStyle}>{formatDate(nc.date)}</td><td style={tdStyle}>{nc.dept}</td><td style={tdStyle}>{nc.type}</td><td style={{...tdStyle,color:nc.severity==="\u91cd\u5927"?"#ef4444":"#d97706",fontWeight:700}}>{nc.severity}</td><td style={tdStyle}>{nc.description.substring(0,20)}{nc.description.length>20?"...":""}</td><td style={tdStyle}>{nc.responsible}</td><td style={tdStyle}>{formatDate(nc.dueDate)}</td><td style={{...tdStyle,color:nc.status==="\u5df2\u95dc\u9589"?"#16a34a":nc.status==="\u8655\u7406\u4e2d"?"#d97706":"#ef4444",fontWeight:700}}>{nc.status}</td></tr>))}</tbody></table>')
lines.append('            <div style={conStyle}>\u7a3d\u6838\u7d50\u8ad6\uff1a\u5171 {ncs.length} \u7b46\u4e0d\u7b26\u5408\u5831\u544a\uff0c\u5c1a\u672a\u95dc\u9589 <b style={{color:"#ef4444"}}>{openNcs}</b> \u7b46\u3002{openNcs>0&&" [\u8b66\u544a] \u8acb\u76e3\u63a7\u672a\u95dc\u9589\u9805\u76ee\u4e4b\u77ef\u6b63\u63aa\u65bd\u57f7\u884c\u9032\u5ea6\u3002"}</div>')
lines.append('          </div>')
lines.append('          {/* \u516d\u3001\u5167\u90e8\u7a3d\u6838 MP-09 */}')
lines.append('          <div style={{ marginBottom:24 }}>')
lines.append('            <div style={{ ...secStyle, borderLeft:"4px solid #8b5cf6" }}>\u516d\u3001\u5167\u90e8\u7a3d\u6838\u7ba1\u7406\uff08MP-09\uff09\u57f7\u884c\u6458\u8981</div>')
lines.append('            <div style={conStyle}>\u5167\u90e8\u7a3d\u6838\u5df2\u5b8c\u6210 <b>{auditCompleted}</b> \u6b21 / \u8a08\u756b <b>{auditTotal}</b> \u6b21\uff0c\u5b8c\u6210\u7387 <b>{auditTotal>0?Math.round(auditCompleted/auditTotal*100):0}%</b>\u3002\u7d2f\u8a08\u767c\u73fe {auditPlans.reduce((s,a)=>s+a.findings,0)} \u9805\uff0c\u4e0d\u7b26\u5408 {auditPlans.reduce((s,a)=>s+a.ncCount,0)} \u9805\u3002</div>')
lines.append('          </div>')
lines.append('          {/* \u4e03\u3001\u74b0\u5883\u76e3\u63a7 MP-06 */}')
lines.append('          <div style={{ marginBottom:24 }}>')
lines.append('            <div style={{ ...secStyle, borderLeft:"4px solid #14b8a6" }}>\u4e03\u3001\u5de5\u4f5c\u74b0\u5883\u76e3\u63a7\uff08MP-06\uff09\u7a3d\u6838\u6458\u8981</div>')
lines.append('            <div style={conStyle}>\u6f54\u6de8\u5ba4\u74b0\u5883\u76e3\u6e2c\u5171 {envRecords.length} \u7b46\uff0c\u6574\u9ad4\u5408\u683c\u7387 <b style={{color:envPassRate>=90?"#16a34a":envPassRate>=80?"#d97706":"#ef4444"}}>{envPassRate}%</b>\uff0c\u4e0d\u5408\u683c <b style={{color:"#ef4444"}}>{envRecords.filter(r=>r.result==="\u4e0d\u5408\u683c").length}</b> \u7b46\uff0c\u8b66\u544a <b style={{color:"#d97706"}}>{envRecords.filter(r=>r.result==="\u8b66\u544a").length}</b> \u7b46\u3002</div>')
lines.append('          </div>')
lines.append('          <div style={{ borderTop:"1px solid #e2e8f0", paddingTop:16, marginTop:24, display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:16 }}>')
lines.append('            {["\u7a3d\u6838\u54e1","\u5be9\u6838\u8005","\u6838\u51c6\u8005"].map(role => (<div key={role} style={{ textAlign:"center" }}><div style={{ height:40, borderBottom:"1px solid #374151" }} /><div style={{ fontSize:12, color:"#6b7280", marginTop:6 }}>{role}\uff08\u7c3d\u540d\uff09</div></div>))}')
lines.append('          </div>')
lines.append('        </div>')
lines.append('      )}')
lines.append('    </div>')
lines.append('  );')
lines.append('}')

content = '\n'.join(lines) + '\n'
with open(r'C:\Users\USER\Desktop\自動稽核程式\audit-dashboard.jsx', 'a', encoding='utf-8-sig') as f:
    f.write(content)
print('Part8 ReportTab OK')
